const input = $input.first().json;
const body = input.body ?? input;
const job = body.job ?? {};
const eventId = body.event?.id ?? body.eventId;
const jobId = job.id ?? body.jobId;
const callbackUrl = body.callbackUrl;
const callbackSecret = body.callbackSecret;
const selectedIdea = (job.ideas ?? []).find((idea) => idea.id === (job.selectedIdeaId ?? body.selectedIdeaId)) ?? (job.ideas ?? [])[0] ?? null;
if (!jobId || !eventId || !callbackUrl) {
  return [];
}

const seedKeyword = job.seedKeyword ?? body.seedKeyword ?? 'Untitled topic';
const title = selectedIdea?.title ?? seedKeyword;
const angle = selectedIdea?.angle ?? 'Build a practical SEO brief';
const relatedKeywords = Array.isArray(selectedIdea?.relatedKeywords) ? selectedIdea.relatedKeywords : [];
const research = job.research ?? { objective: '', audience: '', gaps: [], sources: [] };
const sources = Array.isArray(research.sources) ? research.sources : [];
const thaiSource = sources.find((source) => source.region === 'TH') ?? sources[0] ?? null;
const globalSource = sources.find((source) => source.region === 'Global') ?? sources[1] ?? sources[0] ?? null;

function slugify(value) {
  return String(value)
    .normalize('NFKC')
    .replace(/[^\p{Letter}\p{Number}\s-]/gu, '')
    .trim()
    .replace(/\s+/g, '-') || 'seo-article';
}

const seoTitle = title.includes('?')
  ? `${title} พร้อมคำอธิบายที่ใช้งานได้จริง`
  : `${title} คืออะไร และควรเริ่มจากตรงไหน`;
const metaDescription = [
  `สรุป ${title} จากข้อมูลไทยและต่างประเทศ`,
  angle,
  'พร้อมวิธีนำไปใช้ ข้อควรระวัง และคำถามที่คนค้นต่อจริง'
].join(' ');
const outline = [
  `${title}: คำตอบสั้นและภาพรวมที่ควรรู้`,
  `สิ่งที่ต้องเข้าใจก่อนลงมือเรื่อง ${seedKeyword}`,
  thaiSource ? `สิ่งที่แหล่งไทยสะท้อนเกี่ยวกับ ${title}` : `มุมมองแบบไทยที่ควรเข้าใจเกี่ยวกับ ${title}`,
  globalSource ? 'สิ่งที่แหล่งต่างประเทศใช้ยืนยันประเด็นนี้' : `แนวทางจากต่างประเทศที่ช่วยให้เนื้อหาครบขึ้น`,
  `วิธีนำข้อมูลเรื่อง ${title} ไปใช้จริงแบบไม่เสี่ยง`,
  'คำถามที่คนค้นต่อจากหัวข้อนี้'
];
const faqs = [
  `${seedKeyword} ต้องเช็กอะไรเป็นอย่างแรก`,
  `${title} ควรระวังความเข้าใจผิดเรื่องไหน`,
  `มีสัญญาณอะไรที่บอกว่าควรรีบจัดการเรื่อง ${title}`
];
const internalLinks = [...new Set([
  `คู่มือพื้นฐานเกี่ยวกับ ${seedKeyword}`,
  `วิธีดูแล ${seedKeyword} สำหรับมือใหม่`,
  ...relatedKeywords.slice(0, 3)
])];

const brief = {
  title: seoTitle,
  slug: slugify(title),
  metaTitle: seoTitle,
  metaDescription,
  audience: research.audience || `Readers searching for ${seedKeyword}`,
  angle,
  outline,
  faqs,
  internalLinks,
  publishStatus: 'draft',
  categoryIds: [],
  tagIds: [],
  featuredImageUrl: ''
};

const callbackResponse = await fetch(callbackUrl, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    ...(callbackSecret ? { 'x-callback-secret': callbackSecret } : {})
  },
  body: JSON.stringify({
    eventId,
    jobId,
    type: 'brief',
    status: 'succeeded',
    workflowRunId: $execution.id,
    message: 'Brief workflow completed in n8n poller.',
    stage: 'brief_ready',
    payload: { provider: 'n8n-poller', executionId: $execution.id },
    brief
  })
});

if (!callbackResponse.ok) {
  throw new Error(`Brief callback failed with status ${callbackResponse.status}`);
}

return [];
